sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var body = request.body;
    if (gs.nil(body) || gs.nil(body.data)) {
        var badReq = new sn_ws_err.ServiceError();
        badReq.setStatus(400);
        badReq.setMessage('Request body must include a data object');
        throw badReq;
    }
    var requestData = body.data;
    var nfId = requestData.nextform_id;
    if (gs.nil(nfId)) {
        var missingId = new sn_ws_err.ServiceError();
        missingId.setStatus(400);
        missingId.setMessage('nextform_id is required in request body data');
        throw missingId;
    }
    var nfData = requestData.nextform_data;
    var result = new NFAPIHelper().process(nfId, nfData, requestData.metadata);
    response.setBody(result);
})(request, response);
